const targetLang = await input.text(
  "Translate to which language?",
);

if (targetLang.length == 0) return;

const BATCH_SIZE = 20;
const POLL_INTERVAL = 1500;
const DEFAULT_RETRY_AFTER_MS = 60000;

let rateLimited = false;
let rateLimitPopupShown = false;
let isProcessing = false;

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function chunk(arr, size) {
  const result = [];
  for (let i = 0; i < arr.length; i += size) {
    result.push(arr.slice(i, i + size));
  }
  return result;
}

function isRateLimitError(err) {
  const message = String(err?.message || err || "").toLowerCase();
  return (
    message.includes("429") ||
    message.includes("rate limit") ||
    message.includes("too many requests")
  );
}

function getRetryAfterMs(err) {
  const message = String(err?.message || err || "");
  const headerMatch = message.match(/retry-after[:=]\s*(\d+)/i);
  if (headerMatch) return Number(headerMatch[1]) * 1000;
  const bodyMatch = message.match(/retry[_-]?after["']?\s*[:=]\s*(\d+)/i);
  if (bodyMatch) return Number(bodyMatch[1]) * 1000;
  return null;
}

async function enterRateLimitMode(waitMs) {
  if (rateLimited) return;
  rateLimited = true;
  spinner.hide();
  const seconds = Math.ceil(waitMs / 1000);
  if (!rateLimitPopupShown) {
    rateLimitPopupShown = true;
    popup.error(`Model rate limit reached. Paused for ${seconds} seconds.`);
  }
  console.warn(`Rate limited. Waiting ${seconds}s`);
  await sleep(waitMs);
  rateLimited = false;
  rateLimitPopupShown = false;
  popup.success("Translation resumed.");
}

/**
 * ==========================================================
 * DETECT CAPTCHA / CLOUDFLARE PAGES
 * ==========================================================
 */
const pageTitle = (await page.getTitle() || "").toLowerCase();
const pageURL   = (await page.getURL()   || "").toLowerCase();

const BLOCKED_KEYWORDS = [
  "captcha",
  "cloudflare",
  "verification",
  "security check",
  "are you human",
];

if (BLOCKED_KEYWORDS.some(kw => pageTitle.includes(kw) || pageURL.includes(kw))) {
  popup.error("Translation disabled on verification pages.");
  return;
}

/**
 * ==========================================================
 * TAG AND SELECTOR FILTERS FOR TEXT EXTRACTION
 * ==========================================================
 */
const SKIP_TAGS = [
  "SCRIPT", "STYLE", "NOSCRIPT",
  "CODE", "PRE", "KBD", "SAMP", "VAR", "TT",
  "TEXTAREA", "INPUT", "SELECT", "OPTION",
  "SVG", "CANVAS", "MATH",
  "NAV", "HEADER", "FOOTER", "ASIDE",
];

const SKIP_ANCESTOR_SELECTORS = [
  "pre", "code", "kbd", "samp",
  ".shiki", ".highlight", ".prism-code", ".hljs",
  ".token", ".code-block", ".codeblock",
  "[class*='language-']", "[class*='lang-']",
  ".gatsby-highlight", ".remark-code-container",
  ".notion-code", ".notion-equation",
  "nav", "header", "footer", "aside",
];

const CODE_KEYWORDS = new Set([
  "null","undefined","true","false","NaN","Infinity",
  "function","return","const","let","var","if","else",
  "for","while","do","switch","case","break","continue",
  "class","extends","new","this","super","import","export",
  "default","async","await","try","catch","finally","throw",
  "typeof","instanceof","void","delete","in","of","yield",
  "static","get","set","public","private","protected",
  "interface","type","enum","namespace","module","declare",
]);

/**
 * ==========================================================
 * TEXT NODE EXTRACTION AND FILTERING
 * ==========================================================
 */
async function getVisibleTextNodes() {
  const allTextNodes = await dom.getVisibleTextNodes({
    skipTags: SKIP_TAGS,
    skipAncestorSelectors: SKIP_ANCESTOR_SELECTORS,
    ignoreCode: true
  });

  const filtered = [];

  for (const node of allTextNodes) {
    const text = node.text.trim();

    if (text.length < 3) continue;
    if (looksLikeCode(text)) continue;

    filtered.push(node);
  }

  return filtered;
}

function looksLikeCode(text) {
  const s = text.trim();

  if (/^https?:\/\/\S+$/.test(s)) return true;
  if (/^([a-z0-9-]+\.)+[a-z]{2,}(\/\S*)?$/i.test(s)) return true;
  if (/^\.{0,2}[/\\][^\s]{2,}$/.test(s)) return true;
  if (/^[$#]\s+\S/.test(s)) return true;
  if (/^(import|require|from)\s+['"`]/.test(s)) return true;
  if (/^import\s+[{*a-zA-Z]/.test(s)) return true;
  if (/^#!\//.test(s)) return true;
  if (/^#[0-9a-fA-F]{3,8}$/.test(s)) return true;
  if (/^[a-z][a-z0-9-]*$/.test(s) && s.includes("-") && s.length <= 60) return true;
  if (/^[a-z][a-zA-Z0-9]*[A-Z][a-zA-Z0-9]*$/.test(s)) return true;
  if (/^[A-Z][a-zA-Z0-9]+$/.test(s) && !/\s/.test(s) && s.length <= 50) return true;
  if (/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(s) && s.includes("_")) return true;
  if (/^v?\d+\.\d+(\.\d+)?(-[\w.]+)?$/.test(s)) return true;
  if (/^[=!<>|&+\-*/^%~?:;,.()\[\]{}'"` ]+$/.test(s) && s.length <= 10) return true;
  if (CODE_KEYWORDS.has(s)) return true;

  return false;
}

/**
 * ==========================================================
 * PATCH TEXT NODES
 * ==========================================================
 */
async function patchNodes(updates) {
  const validUpdates = updates
    .filter(item => !item.skip)
    .map(item => ({
      id: item.id,
      text: item.text
    }));

  if (validUpdates.length === 0) return;

  await dom.patchTextNodes(validUpdates);
}

/**
 * ==========================================================
 * TRANSLATE BATCH
 * ==========================================================
 */
async function translateBatch(batch) {
  const payload = batch
    .map(item => `NODE_ID:${item.id}\nTEXT:\n${item.text}\nEND_NODE`)
    .join("\n\n");

  try {
    const response = await ai.chat([
      {
        role: "system",
        content: `You are a professional translator. Translate all text into ${targetLang}.

═══════════════════════════════════════
WHAT YOU MUST NEVER TRANSLATE
═══════════════════════════════════════

Leave the following COMPLETELY UNCHANGED — return them exactly as received:

• URLs and domain names          e.g. https://example.com  github.com
• File paths                     e.g. /usr/bin/node  ./src/index.js
• Shell / terminal commands      e.g. npm install react  git commit -m "fix"
• Package names                  e.g. react  lodash  numpy  @types/node
• Import / require statements    e.g. import React from 'react'
• Function names                 e.g. handleClick  getUserById
• Class names                    e.g. UserService  HttpClient
• Variable / constant names      e.g. MAX_RETRIES  isLoading
• Code keywords                  e.g. const  async  null  undefined
• Version strings                e.g. v1.2.3  2.0.0-beta
• Hex colours                    e.g. #ff0000  #1a2b3c
• Operators / punctuation        e.g. =>  &&  !==
• Any text that is clearly code

If a node is entirely untranslatable code, mark it with TYPE:skip and return the original text unchanged.

═══════════════════════════════════════
FORMAT — return EXACTLY this, no deviations
═══════════════════════════════════════

NODE_ID:<id>
TYPE:<prose|skip>
TEXT:
<translated text, or original if skip>
END_NODE

Rules:
1. Output every input node — never drop one.
2. Never merge or split nodes.
3. Never modify NODE_ID values.
4. No markdown, no commentary, no extra blank lines outside the block.
5. Preserve leading/trailing whitespace and punctuation exactly.`,
      },
      {
        role: "user",
        content: payload,
      },
    ]);

    const regex = /NODE_ID:(.*?)\n(?:TYPE:(.*?)\n)?TEXT:\n([\s\S]*?)\nEND_NODE/g;
    const updates = [];
    let match;

    while ((match = regex.exec(response)) !== null) {
      const id   = match[1].trim();
      const type = (match[2] || "prose").trim().toLowerCase();
      const text = match[3].trim();
      updates.push({ id, text, skip: type === "skip" });
    }

    return updates;
  } catch (err) {
    if (isRateLimitError(err)) {
      const waitMs = getRetryAfterMs(err) ?? DEFAULT_RETRY_AFTER_MS;
      await enterRateLimitMode(waitMs);
      return [];
    }
    throw err;
  }
}

/**
 * ==========================================================
 * PROCESS CURRENT VIEWPORT
 * ==========================================================
 */
async function processViewport() {
  if (isProcessing) return;
  if (rateLimited)  return;

  isProcessing = true;

  try {
    const nodes = await getVisibleTextNodes();
    if (!nodes.length) return;

    const batches = chunk(nodes, BATCH_SIZE);
    spinner.show(`Translating ${nodes.length} text blocks...`);

    for (let i = 0; i < batches.length; i++) {
      if (rateLimited) break;

      spinner.update(`Translating batch ${i + 1}/${batches.length}`);

      try {
        const updates = await translateBatch(batches[i]);
        if (updates.length) await patchNodes(updates);
      } catch (err) {
        console.error(err);
      }
    }

    spinner.hide();
  } finally {
    isProcessing = false;
  }
}

/**
 * ==========================================================
 * INITIAL PASS
 * ==========================================================
 */
await processViewport();

popup.success(`Lazy translation enabled (${targetLang})`);

/**
 * ==========================================================
 * SCROLL-BASED LAZY TRANSLATION
 * ==========================================================
 */
setInterval(async () => {
  try {
    await processViewport();
  } catch (err) {
    console.error(err);
  }
}, POLL_INTERVAL);
